import stylesText from './review-card.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import type { Card } from '@motivation/shared';
import { API_URL } from '../../../config.js';

const styles = cssStyleSheet(stylesText);
import { createCardFlippedEvent } from '../vietnamese-events.js';

const reviewCardTemplate = document.createElement('template');
reviewCardTemplate.innerHTML = `
    <div class="card-container">
        <div class="card-inner">
            <div class="card-face card-front" aria-live="polite">
            </div>
            <div class="card-face card-back" aria-live="polite">
            </div>
        </div>
        <button class="audio-btn" hidden aria-label="Play audio">
            <span class="audio-icon">🔊</span>
        </button>
    </div>
`;

export class ReviewCard extends HTMLElement {
    private _card?: Card;
    private flipped: boolean = false;
    private audio: HTMLAudioElement | null = null;
    private audioState: 'idle' | 'loading' | 'playing' | 'error' = 'idle';

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        this.shadowRoot!.adoptedStyleSheets = [styles];
        this.render();
    }

    connectedCallback() {
        this.addEventListener('click', this.handleInteract);
        this.shadowRoot!.addEventListener('click', this.handleAudioClick);
        if (this._card) {
            this.updateContent();
            this.updateAudioButton();
        }
    }

    disconnectedCallback() {
        this.removeEventListener('click', this.handleInteract);
        this.shadowRoot!.removeEventListener('click', this.handleAudioClick);
        this.stopAudio();
    }

    private handleInteract = () => {
        if (!this.flipped) {
            this.flipped = true;
            this.renderFlippedState();

            this.dispatchEvent(createCardFlippedEvent());
        }
    };

    private handleAudioClick = (e: Event) => {
        const target = e.target as HTMLElement;
        const btn = target.closest('.audio-btn');
        if (!btn) return;

        // Prevent the card flip from triggering
        e.stopPropagation();

        if (this.audioState === 'playing') {
            this.stopAudio();
        } else {
            this.playAudio();
        }
    };

    /**
     * Resets the card to the un-flipped state.
     * Useful when navigating to the next card.
     */
    public resetFlip() {
        this.flipped = false;
        this.renderFlippedState();
    }

    public showCard(card: Card) {
        const inner = this.shadowRoot?.querySelector('.card-inner') as HTMLElement | null;
        if (inner) {
            inner.style.transition = 'none';
        }

        this.flipped = false;
        this.renderFlippedState();
        this._card = card;

        this.stopAudio();
        this.updateContent();
        this.updateAudioButton();

        if (inner) {
            void inner.offsetWidth;
            inner.style.transition = '';
        }
    }

    private playAudio() {
        if (!this._card?.audio) return;

        this.stopAudio();

        const currentAudio = new Audio(`${API_URL}/api/media/audio/${this._card.audio}`);
        this.audio = currentAudio;
        this.setAudioState('loading');

        currentAudio.addEventListener('playing', () => {
            if (this.audio !== currentAudio) return;
            this.setAudioState('playing');
        });

        currentAudio.addEventListener('ended', () => {
            if (this.audio !== currentAudio) return;
            this.setAudioState('idle');
        });

        currentAudio.addEventListener('error', () => {
            if (this.audio !== currentAudio) return;
            this.setAudioState('error');
        });

        currentAudio.play().catch(() => {
            if (this.audio !== currentAudio) return;
            this.setAudioState('error');
        });
    }

    private stopAudio() {
        if (this.audio) {
            this.audio.pause();
            this.audio.src = '';
            this.audio = null;
        }
        this.setAudioState('idle');
    }

    private setAudioState(state: 'idle' | 'loading' | 'playing' | 'error') {
        this.audioState = state;
        const btn = this.shadowRoot?.querySelector('.audio-btn') as HTMLElement | null;
        if (!btn) return;

        btn.setAttribute('data-state', state);
        const icon = btn.querySelector('.audio-icon') as HTMLElement | null;
        if (icon) {
            switch (state) {
                case 'idle': icon.textContent = '🔊'; break;
                case 'loading': icon.textContent = '⏳'; break;
                case 'playing': icon.textContent = '⏹️'; break;
                case 'error': icon.textContent = '🔇'; break;
            }
        }
    }

    private updateAudioButton() {
        const btn = this.shadowRoot?.querySelector('.audio-btn') as HTMLElement | null;
        if (!btn) return;

        if (this._card?.audio) {
            btn.hidden = false;
        } else {
            btn.hidden = true;
            this.stopAudio();
        }
    }

    private render() {
        this.shadowRoot!.appendChild(reviewCardTemplate.content.cloneNode(true));
        this.updateContent();
    }

    private updateContent() {
        if (!this.shadowRoot || !this._card) return;
        const frontEl = this.shadowRoot.querySelector('.card-front') as HTMLElement;
        const backEl = this.shadowRoot.querySelector('.card-back') as HTMLElement;
        
        if (frontEl) frontEl.textContent = this._card.front;
        if (backEl) backEl.textContent = this._card.back;
    }

    private renderFlippedState() {
        const inner = this.shadowRoot?.querySelector('.card-inner') as HTMLElement;
        if (inner) {
            if (this.flipped) {
                inner.classList.add('is-flipped');
            } else {
                inner.classList.remove('is-flipped');
            }
        }
    }
}

customElements.define('review-card', ReviewCard);
