import stylesText from './review-session-summary.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { goBack } from '../../../router.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="summary-view">
        <h2 id="summary-title">Session Complete</h2>
        <p id="empty-msg" hidden>There are no cards due for review right now.</p>

        <div class="stat-box" id="stat-box">
            <div class="stat">
                <span class="stat-value" id="val-reviewed">0</span>
                <span class="stat-label">Cards Reviewed</span>
            </div>
            <div class="stat">
                <span class="stat-value" id="val-average">0.0</span>
                <span class="stat-label">Average Rating</span>
            </div>
        </div>

        <button type="button" class="btn-return" id="btn-return">Return to Dashboard</button>
    </div>
`;

export interface ReviewSessionStats {
    reviewed: number;
    average: number;
}

export class ReviewSessionSummary extends HTMLElement {
    private _stats?: ReviewSessionStats;

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        this.shadowRoot!.adoptedStyleSheets = [styles];
    }

    connectedCallback() {
        this.render();
    }

    set stats(val: ReviewSessionStats | undefined) {
        this._stats = val;
        if (this.isConnected) {
            this.updateContent();
        }
    }

    get stats(): ReviewSessionStats | undefined {
        return this._stats;
    }



    private render() {
        this.shadowRoot!.appendChild(template.content.cloneNode(true));
        this.shadowRoot!.getElementById('btn-return')!.addEventListener('click', () => {
            goBack('/vietnamese');
        });
        this.updateContent();
    }

    private updateContent() {
        if (!this.shadowRoot || !this._stats) return;
        
        const emptyMsg = this.shadowRoot.getElementById('empty-msg')!;
        const statBox = this.shadowRoot.getElementById('stat-box')!;
        const title = this.shadowRoot.getElementById('summary-title')!;
        
        if (this._stats.reviewed === 0) {
            title.textContent = 'All Caught Up!';
            emptyMsg.hidden = false;
            statBox.hidden = true;
        } else {
            title.textContent = 'Session Complete';
            emptyMsg.hidden = true;
            statBox.hidden = false;
            
            this.shadowRoot.getElementById('val-reviewed')!.textContent = this._stats.reviewed.toString();
            this.shadowRoot.getElementById('val-average')!.textContent = this._stats.average.toFixed(1);
        }
    }
}

customElements.define('review-session-summary', ReviewSessionSummary);
